			lowerBound := int64(0)

			// Neighbors are not target peaks, so their final values are their initial values.
			lowerBound = max(nums[i-1], nums[i+1])

			requiredValue := lowerBound + 1

			if currentNums[i] < requiredValue {
				cost := requiredValue - currentNums[i]
				totalCost += cost
				currentNums[i] = requiredValue
			}
		}
		return totalCost
	}

	// --- Candidate 1: Peaks starting at index 1 ---
	peaks1 := []int{}
	for i := 1; i <= n-2; i += 2 {
		peaks1 = append(peaks1, i)
	}
	cost1 := calculateCost(peaks1)
	minTotalCost = min(minTotalCost, cost1)

	// --- Candidate 2: Peaks starting at index 2 ---
	peaks2 := []int{}
	for i := 2; i <= n-2; i += 2 {
		peaks2 = append(peaks2, i)
	}
	cost2 := calculateCost(peaks2)
	minTotalCost = min(minTotalCost, cost2)

	// Edge Case Check: If KMax = 1, both candidates might yield K=1, but we might miss other K=1 configurations.
	// However, if we can achieve K_max, we must find the minimum cost for *that* K_max.
	// If K_max=1, the optimal single peak $i$ is the one requiring minimum cost.
	if KMax == 1 {
		minCostK1 := int64(math.MaxInt64)
		for i := 1; i <= n-2; i++ {
			// Calculate cost for peak at i only
			lowerBound := max(nums[i-1], nums[i+1])
			requiredValue := lowerBound + 1
