	// The two alternating sequences cover all configurations achieving K_max.

	return minTotalCost
}

func max(a, b int64) int64 {
	if a > b {
		return a
	}
	return b
}

func min(a, b int64) int64 {
	if a < b {
		return a
	}
	return b
